const System = Java.type('java.lang.System')
const JSONObject = Java.type('com.alibaba.fastjson.JSONObject')

// 获取要执行的逻辑编排
const flowId = context.get('__flowId');
const taskId = context.get('__taskId');
const instanceId = context.get('__instanceId');
let variables = getResult('variables')
klog.info(`[X-TASK]-[${taskId}]-[task_agent]开始执行`)
if (!variables) {
 variables = {}
}

// 加入系统变量
const currentVariables = JSONObject.toJSON(context)
const sysVariables = JSON.parse(currentVariables);
variables['sys'] = sysVariables['sys']
variables['request'] = sysVariables['request']
const taskInstanceId = instanceId + "." + taskId
variables['_taskId'] = taskId
let t1 = System.currentTimeMillis()
const lck = kutils.getCache('x-task', taskInstanceId);
const lockTime = parseInt(lck)

// 执行历史
const taskInfo = getResult("taskInfo")
const taskHistory = {
 id: getUuid(),
 taskId: taskId,
 taskName: taskInfo["name"],
 executeBeginTime: dateFormat(new Date(), "yyyy-MM-dd HH:mm:ss"),
 requestBody: taskInfo["taskArgv"]
}

if (lck && ((t1 - lockTime) < 1000 * 60 * 10)) {
 klog.info(`[X-TASK]-[${taskInstanceId}]-[task_agent]任务正在执行中，将跳过此次执行`)
}
else {
 let lastExecuteStatus = 1;
 let errorMessage = '';
 try {
 kutils.setCache('x-task', taskInstanceId, t1 + '', 1000 * 60 * 10)
 kutils.dbCommand('MySql', 'update sys_task set last_execute_time=?, last_execute_status=? where id=?', [context.get('sys').get('when'), 2, taskId])
 klog.info(`[X-TASK]-[${taskInstanceId}]-[task_agent]执行变量:` + JSON.stringify(variables))
 const s = kutils.callFlow(flowId, JSON.stringify(variables));
 // 获取执行结果
 taskHistory["responseBody"] = s.data

 klog.info(`[X-TASK]-[${taskInstanceId}]-[task_agent]执行完成`)
 if (s.status != 0) {
 errorMessage = s.errorMsg;
 lastExecuteStatus = 0;
 }
 }
 catch (e) {
 const errorDetails = e instanceof Error ? `` : JSON.stringify(e);
 klog.info(`[X-TASK]-[${taskInstanceId}]-[task_agent]执行异常: ` + e);
 errorMessage = errorDetails;
 lastExecuteStatus = 0;
 }
 finally {
 kutils.removeCache('x-task', taskInstanceId)
 }
 let t2 = System.currentTimeMillis()
 if (lastExecuteStatus == 0) {
 const sql = "update sys_task set last_execute_status=?, last_execute_take = ?, last_execute_msg = ? where id=?";
 const params = [lastExecuteStatus, (t2 - t1), errorMessage, taskId]
 kutils.dbCommand('MySql', sql, params)
 }
 else {
 const sql = "update sys_task set last_execute_status=?, last_execute_take = ? where id=?";
 const params = [lastExecuteStatus, (t2 - t1), taskId]
 kutils.dbCommand('MySql', sql, params)
 }


 klog.info(`[X-TASK]-[]-[task_agent]开始结束`)

 // 执行历史
 taskHistory["executeStatus"] = lastExecuteStatus
 taskHistory["executeTake"] = t2 - t1
 taskHistory["executeMsg"] = errorMessage
 taskHistory["executeEndTime"] = dateFormat(new Date(), "yyyy-MM-dd HH:mm:ss")

 setResult("taskHistory", taskHistory)
}

const list = toHumpResult();
// 获取任务信息
let taskInfo = {}
let taskExist = false
if (list.length > 0) {
 taskInfo = list[0]
 taskExist = true
}
setResult("taskInfo", taskInfo)
setResult("taskExist", taskExist)

// 获取任务 id
const taskId = context.get('__taskId');
setResult("taskId", taskId)

const taskExist = getResult("taskExist")
const taskHistory = getResult("taskHistory")
const nowStr = dateFormat(new Date(), "yyyy-MM-dd HH:mm:ss")

const sql = `insert into sys_task_history (id, task_id, task_name, execute_status, execute_take, execute_begin_time, execute_end_time, execute_msg, request_body, response_body, when_created, when_modified) values (?,?,?,?,?,?,?,?,?,?,?,?)`
const params = [ 
 taskHistory["id"],
 taskHistory["taskId"],
 taskHistory["taskName"],
 taskHistory["executeStatus"],
 taskHistory["executeTake"],
 taskHistory["executeBeginTime"],
 taskHistory["executeEndTime"],
 taskHistory["executeMsg"],
 taskHistory["requestBody"],
 taskHistory["responseBody"],
 nowStr,
 nowStr
]

try {
 // 防止旧版没有历史表的定时任务会报错，这里异常也不影响
 let existTable = kutils.getCache('existTable', 'sys_task_history')

 if (existTable == null) {
 const status = kutils.getTableMeta('MySql', "sys_task_history").status
 if (status == 0) {
 existTable = "true"
 } else {
 existTable = "false"
 }
 kutils.setCache('existTable', 'sys_task_history', existTable)
 } 
 klog.info("existTable: " + existTable)
 // 存在表，记录历史
 // 不存在表，那么不记录历史
 if (existTable == "true") {
 const result = kutils.dbCommand('MySql', sql, params)
 klog.info(result)
 }
} catch(e) {
}
